import React, { useState } from 'react';
import axios from 'axios';

const InputForm = ({ setReport }) => {
    const [formData, setFormData] = useState({ hours: '', attendance: '', marks: '' });

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            // Talking to your FastAPI backend
            const response = await axios.post('http://127.0.0.1:8000/predict', formData);
            setReport(response.data);
        } catch (error) {
            console.error("Error fetching prediction:", error);
        }
    };

    return (
        <div className="form-container">
            <h2>Analyze Your Performance</h2>
            <form onSubmit={handleSubmit}>
                <input type="number" placeholder="Study Hours" onChange={(e) => setFormData({...formData, hours: e.target.value})} />
                <input type="number" placeholder="Attendance %" onChange={(e) => setFormData({...formData, attendance: e.target.value})} />
                <input type="number" placeholder="Previous Marks" onChange={(e) => setFormData({...formData, marks: e.target.value})} />
                <button type="submit">Predict Score</button>
            </form>
        </div>
    );
};

export default InputForm;
